<div class="d-flex justify-content-between align-items-center mb-3"><h1>Service Territories</h1></div><div class="row g-4"><div class="col-lg-5"><div class="card p-3"><form method="post"><?=csrf_field()?><label class="form-label">Name</label><input class="form-control mb-2" name="name" required><label class="form-label">Type</label><select class="form-select mb-2" name="territory_type"><option value="postal_code">Postal code</option><option value="city">City</option><option value="radius">Radius</option></select><div class="row"><div class="col"><input class="form-control" name="city" placeholder="City"></div><div class="col"><input class="form-control" name="state" value="NE" maxlength="2"></div></div><input class="form-control my-2" name="postal_code" placeholder="Postal code"><div class="row"><div class="col"><input class="form-control" name="center_lat" placeholder="Latitude"></div><div class="col"><input class="form-control" name="center_lng" placeholder="Longitude"></div></div><input class="form-control my-2" name="radius_miles" placeholder="Radius miles"><input class="form-control mb-2" type="number" step=".01" name="travel_surcharge" placeholder="Travel surcharge"><label><input type="checkbox" name="active" checked> Active</label><button class="btn btn-primary w-100 mt-3">Save Territory</button></form></div></div><div class="col-lg-7"><div class="card"><table class="table mb-0"><thead><tr><th>Name</th><th>Type</th><th>Area</th><th>Surcharge</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><?=e($r['name'])?></td><td><?=e($r['territory_type'])?></td><td><?=e($r['postal_code']?:$r['city']?:($r['radius_miles'].' mi'))?></td><td>$<?=number_format((float)$r['travel_surcharge'],2)?></td></tr><?php endforeach?></tbody></table></div></div></div>
